{
    long long int i, b;
    long long int count=0;
    long long int flag=0;
    scanf("%lld", &b);
    for(i=1; i*i<=b; i++)
    {
        if(b%i==0)
            count++;
        if(i*i==b)
            flag=1;
    }
    if(flag==0)
        count=(2*count);
    else
        count=((2*count)-1);
    printf("%lld\n", count);
    return 0;
}

