mod util {
    use std;
    pub fn read_line() -> String {
        let mut buffer = String::new();
        std::io::stdin().read_line(&mut buffer).unwrap();
        String::from(buffer.trim_right())
    }
    #[allow(dead_code)]
    pub fn read_ascii() -> Vec<u8> {
        let line = read_line();
        debug_assert!(line.is_ascii());
        line.bytes().collect()
    }
    #[allow(dead_code)]
    pub fn read1() -> i64 {
        read_line().parse::<i64>().unwrap()
    }
    #[allow(dead_code)]
    fn read_nums<T: std::str::FromStr>() -> Vec<T>
        where <T as std::str::FromStr>::Err : std::fmt::Debug {
        read_line().split(' ').map(|x| x.parse::<T>().unwrap()).collect()
    }
    #[allow(dead_code)]
    pub fn read_ints() -> Vec<i64> {
        read_nums::<i64>()
    }
    #[allow(dead_code)]
    pub fn read_floats() -> Vec<f64> {
        read_nums::<f64>()
    }
    #[allow(dead_code)]
    pub fn read2() -> (i64, i64) {
        let nums = read_ints();
        (nums[0], nums[1])
    }
    #[allow(dead_code)]
    pub fn read3() -> (i64, i64, i64) {
        let nums = read_ints();
        (nums[0], nums[1], nums[2])
    }
    #[allow(dead_code)]
    pub fn read4() -> (i64, i64, i64, i64) {
        let nums = read_ints();
        (nums[0], nums[1], nums[2], nums[3])
    }
} // mod util
use util::*;

type Prime = i64;
type Power = usize;
type PrimePower = (Prime, Power);
type Factorization = Vec<PrimePower>;

fn primes_below(maxn: usize) -> Vec<Prime> {
    if maxn <= 2 {
        return vec![];
    }
    let mut is_prime: Vec<bool> = vec![true; maxn];
    is_prime[0] = false;
    is_prime[1] = false;
    let mut iterator: i64 = 2;
    while iterator * iterator < maxn as i64 {
        if is_prime[iterator as usize] {
            let mut destroyer: i64 = iterator * iterator;
            while destroyer < maxn as i64 {
                is_prime[destroyer as usize] = false;
                destroyer += iterator;
            }
        }
        iterator += 1;
    }
    is_prime.iter().enumerate().filter(|pair| *pair.1)
        .map(|pair| pair.0 as Prime).collect()
}

fn naive_factorization(mut number: i64, primes_till_sqrt: &Vec<Prime>) -> Factorization {
    let mut prime_iter: usize = 0;
    let mut prime: Prime;
    let mut answer: Factorization = vec![];
    while number != 1 {
        if prime_iter >= primes_till_sqrt.len() {
            answer.push((number, 1));
            return answer;
        }
        prime = primes_till_sqrt[prime_iter];
        if number % prime == 0 {
            let mut power: Power = 0;
            while number % prime == 0 {
                power += 1;
                number /= prime;
            }
            answer.push((prime, power));
        }
        prime_iter += 1;
    }
    answer
}

fn main() {
    let b = read1();
    let v = primes_below(100000);
    let mut ans = 1;
    for (_p, val) in naive_factorization(b, &v) {
        ans *= (val + 1);
    }
    println!("{}", ans);
}
